/* Blocked tile damage shake */
@keyframes blockedShake {
    0%, 100% { transform: translateX(0); }
    15% { transform: translateX(calc(-1 * var(--shake-intensity))); }
    30% { transform: translateX(var(--shake-intensity)); }
    45% { transform: translateX(calc(-0.7 * var(--shake-intensity))); }
    60% { transform: translateX(calc(0.5 * var(--shake-intensity))); }
    75% { transform: translateX(calc(-0.3 * var(--shake-intensity))); }
}

.gem.shake-light {
    --shake-intensity: 2px;
    animation: blockedShake 0.3s ease-out;
}

.gem.shake-medium {
    --shake-intensity: 4px;
    animation: blockedShake 0.35s ease-out;
}

.gem.shake-heavy {
    --shake-intensity: 6px;
    animation: blockedShake 0.4s ease-out;
}

/* Floating damage text */
@keyframes damageFloat {
    0% {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
    20% {
        opacity: 1;
        transform: translateY(-20%) scale(1.1);
    }
    100% {
        opacity: 0;
        transform: translateY(-80%) scale(0.8);
    }
}

.damage-text {
    position: absolute;
    z-index: 300;
