    15% { transform: translateX(calc(-1 * var(--shake-intensity))); }
    30% { transform: translateX(var(--shake-intensity)); }
    45% { transform: translateX(calc(-0.7 * var(--shake-intensity))); }
    60% { transform: translateX(calc(0.5 * var(--shake-intensity))); }
