    12→} from "./tile-helpers.js";
    13→import { parsePresetTile } from "./serializer.js";
    14→
    15→function isRectangularBlockConfig(blockedPos) {
    16→    return blockedPos.width !== undefined && blockedPos.height !== undefined;
    17→}
    18→
    19→function placeRectangularBlockedTile(game, config) {
    20→    const { row, col, width, height, lifeValue } = config;
    21→
    22→    // Validate bounds
    23→    if (row + height > game.boardHeight || col + width > game.boardWidth) {
    24→        console.warn(`Rectangular blocked tile at (${row},${col}) with size ${width}x${height} exceeds board bounds`);
    25→        return;
    26→    }
    27→
    28→    // Create single shared tile object
    29→    const rectId = `rect_${row}_${col}_${width}_${height}`;
    30→    const sharedTile =
    31→        lifeValue !== undefined
    32→            ? createRectangularBlockedTile(rectId, { row, col }, width, height, lifeValue)
    33→            : createRectangularBlockedWithMergeCount(rectId, { row, col }, width, height);
    34→
    35→    // Place reference in all cells of the rectangle
    36→    for (let r = row; r < row + height; r++) {
    37→        for (let c = col; c < col + width; c++) {
    38→            game.board[r][c] = sharedTile; // All cells point to same object
    39→        }
    40→    }
    41→}
    42→
    43→export function createBoard(game) {
    44→    game.board = [];
    45→
    46→    // Check if there's a boardPreset in the level config
    47→    const levelConfig = game.levelConfig || {};
    48→    const boardPreset = levelConfig.boardPreset;
    49→
    50→    if (boardPreset && Array.isArray(boardPreset)) {
    51→        // Use the preset board configuration
    52→        for (let row = 0; row < game.boardHeight; row++) {
    53→            game.board[row] = [];
    54→            for (let col = 0; col < game.boardWidth; col++) {
    55→                if (boardPreset[row] && boardPreset[row][col] !== undefined) {
    56→                    // Use preset tile
    57→                    game.board[row][col] = parsePresetTile(boardPreset[row][col]);
    58→                } else {
    59→                    // Fill with random tile if preset doesn't cover this position
    60→                    game.board[row][col] = createTile(getRandomTileValue(game));
    61→                }
    62→            }
    63→        }
    64→    } else {
    65→        // Generate random board as before
    66→        for (let row = 0; row < game.boardHeight; row++) {
    67→            game.board[row] = [];
    68→            for (let col = 0; col < game.boardWidth; col++) {
    69→                do {
    70→                    game.board[row][col] = createTile(getRandomTileValue(game));
    71→                } while (hasInitialMatch(game, row, col));
    72→            }
    73→        }
    74→
    75→        // Place blocked tiles (with or without life, movable or immovable) from blockedTiles config
    76→        if (game.blockedTiles) {
    77→            game.blockedTiles.forEach((blockedPos) => {
    78→                // NEW: Handle rectangular blocks
    79→                if (isRectangularBlockConfig(blockedPos)) {
    80→                    placeRectangularBlockedTile(game, blockedPos);
    81→                    return; // Skip rest of iteration
    82→                }
    83→
    84→                // Determine tile creator based on properties
    85→                // movable: true = swappable (BLOCKED_MOVABLE) - can drop and swap
    86→                // movable: false = immovable (blocks gravity)
    87→                // movable: undefined (omitted) = droppable (can fall, cannot swap)
    88→                const movable = blockedPos.movable;
    89→                const immovable = movable === false;
    90→
    91→                let tileCreator;
    92→                if (movable === true) {
    93→                    // Movable blocked tile (swappable)
    94→                    tileCreator = createBlockedMovableTile;
    95→                } else if (blockedPos.lifeValue !== undefined) {
    96→                    // Has life value - create blocked with life tile
    97→                    tileCreator = () => createBlockedWithLifeTile(blockedPos.lifeValue, immovable);
    98→                } else {
    99→                    // Regular blocked tile
   100→                    tileCreator = () => createBlockedTile(immovable);
   101→                }
   102→
   103→                if (blockedPos.row !== undefined && blockedPos.col !== undefined) {
   104→                    const colArray = Array.isArray(blockedPos.col) ? blockedPos.col : [blockedPos.col];
   105→                    for (const col of colArray) {
   106→                        if (blockedPos.row < game.boardHeight && col < game.boardWidth) {
   107→                            game.board[blockedPos.row][col] = tileCreator();
   108→                        }
   109→                    }
   110→                } else if (blockedPos.row !== undefined && blockedPos.col === undefined) {
   111→                    // Entire row: { row: 2 } or { row: 2, lifeValue: 128 } or { row: 2, movable: true }
   112→                    if (blockedPos.row < game.boardHeight) {
   113→                        for (let col = 0; col < game.boardWidth; col++) {
   114→                            game.board[blockedPos.row][col] = tileCreator();
   115→                        }
   116→                    }
   117→                } else if (blockedPos.col !== undefined && blockedPos.row === undefined) {
   118→                    // Entire column: { col: 3 } or { col: 3, lifeValue: 128 } or { col: 3, movable: true }
   119→                    if (blockedPos.col < game.boardWidth) {
   120→                        for (let row = 0; row < game.boardHeight; row++) {
   121→                            game.board[row][blockedPos.col] = tileCreator();
   122→                        }
   123→                    }
   124→                }
   125→            });
   126→        }
   127→    }
   128→}
