   130→export function getRandomTileValue(game) {
   131→    return game.tileValues[Math.floor(Math.random() * game.tileValues.length)];
   132→}
   133→
   134→export function canMatch(tile1, tile2, game) {
   135→    // Helper function to check if two tiles can match
   136→    const val1 = getTileValue(tile1);
   137→    const val2 = getTileValue(tile2);
   138→
   139→    // Normal match: same value
   140→    if (val1 === val2) return true;
   141→
   142→    // Plus tile can match with equal or higher value
   143→    if (isTilePlusTile(tile1) && val2 >= val1) return true;
   144→    if (isTilePlusTile(tile2) && val1 >= val2) return true;
   145→
   146→    return false;
   147→}
   148→
   149→function hasInitialMatch(game, row, col) {
   150→    const tile = game.board[row][col];
   151→    const value = getTileValue(tile);
   152→
   153→    // Check horizontal matches
   154→    if (col >= 2 && game.board[row][col - 1] && game.board[row][col - 2]) {
   155→        const val1 = getTileValue(game.board[row][col - 1]);
   156→        const val2 = getTileValue(game.board[row][col - 2]);
   157→        if (value === val1 && value === val2) {
   158→            return true;
   159→        }
   160→    }
   161→
   162→    // Check vertical matches
   163→    if (row >= 2 && game.board[row - 1][col] && game.board[row - 2][col]) {
   164→        const val1 = getTileValue(game.board[row - 1][col]);
   165→        const val2 = getTileValue(game.board[row - 2][col]);
   166→        if (value === val1 && value === val2) {
   167→            return true;
   168→        }
   169→    }
   170→
   171→    // Check special formations that could be created by placing this tile
   172→    // Note: These will be imported from match-detector.js in the game
   173→    // For now, we'll do a simplified check
   174→
   175→    // We need access to checkTFormation, checkLFormation, checkBlockFormation
   176→    // These will be checked by the game instance
   177→    if (game.checkTFormation && game.checkTFormation(row, col, value)) {
   178→        return true;
   179→    }
   180→
   181→    if (game.checkLFormation && game.checkLFormation(row, col, value)) {
   182→        return true;
   183→    }
   184→
   185→    // Check if this position completes a block formation (check all possible 2x2 blocks this tile could be part of)
   186→    const blockPositions = [
   187→        [row - 1, col - 1], // This tile is bottom-right of block
   188→        [row - 1, col], // This tile is bottom-left of block
   189→        [row, col - 1], // This tile is top-right of block
   190→        [row, col], // This tile is top-left of block
   191→    ];
   192→
   193→    for (const [blockRow, blockCol] of blockPositions) {
   194→        if (game.checkBlockFormation && game.checkBlockFormation(blockRow, blockCol, value)) {
   195→            return true;
   196→        }
   197→    }
   198→
   199→    return false;
   200→}
