    45→    matchGroups.forEach((group) => {
    46→        const displayValue = getDisplayValue(group.value);
    47→        totalScore += displayValue * group.tiles.length;
    48→    });
    49→
    50→    // Update score
    51→    game.score += totalScore;
    52→    game.saveScore(); // Save score to localStorage
    53→
    54→    // Track score towards score goals
    55→    game.levelGoals.forEach((goal) => {
    56→        if (goal.goalType === "score") {
    57→            goal.current += totalScore;
    58→        }
    59→    });
    60→
    61→    // Check for pending formation tutorials (only on user swaps)
    62→    let showedTutorial = false;
    63→    if (wasUserSwap) {
    64→        const pendingTutorials = getPendingFormationTutorials(matchGroups, game.lastSwapPosition);
    65→
    66→        if (pendingTutorials.length > 0) {
    67→            showedTutorial = true;
    68→
    69→            // Highlight all tiles that will be merged and blocked tiles that will be removed
    70→            highlightMergeTiles(matchGroups);
    71→            highlightBlockedTiles(game, matchGroups);
    72→
    73→            // Wait 500ms so user can see the highlighted tiles before dialog opens
    74→            await new Promise((resolve) => setTimeout(resolve, 500));
    75→
    76→            // Show each tutorial dialog and wait for user to close it
    77→            for (const { formationType } of pendingTutorials) {
    78→                await showFormationTutorialDialog(formationType);
    79→            }
    80→
    81→            // Wait 800ms after dialog closes before continuing
    82→            await new Promise((resolve) => setTimeout(resolve, 800));
    83→
    84→            // Clear the highlight
    85→            clearMergeHighlight();
    86→        }
    87→    }
    88→
    89→    // Slow down animations after tutorial so user can see what happens
    90→    const speedMultiplier = showedTutorial ? 2 : 1;
    91→
    92→    // Check for blocked tiles adjacent to original match positions and unblock them
    93→    // Done after tutorial dialogs so blocked tiles are still visible during tutorial
    94→    unblockAdjacentTiles(game, matchGroups, speedMultiplier);
    95→
    96→    // Start merge animations
    97→    animateMerges(game, matchGroups, (matchGroups) => processMerges(game, matchGroups, wasUserSwap), speedMultiplier);
    98→}
    99→
   100→export function processMerges(game, matchGroups, wasUserSwap = false) {
   101→    // Check for sticky free swap tiles BEFORE clearing the board
   102→    matchGroups.forEach((group) => {
   103→        group.hasStickyFreeSwap = group.tiles.some((tile) => {
   104→            const boardTile = game.board[tile.row][tile.col];
   105→            return isTileStickyFreeSwapTile(boardTile);
   106→        });
   107→    });
   108→
   109→    // Track cursed tiles that were successfully merged
   110→    const mergedCursedTiles = [];
   111→    matchGroups.forEach((group) => {
   112→        group.tiles.forEach((tile) => {
   113→            const boardTile = game.board[tile.row][tile.col];
   114→            if (isCursed(boardTile)) {
   115→                mergedCursedTiles.push({ row: tile.row, col: tile.col });
   116→            }
   117→        });
   118→    });
   119→
   120→    // OPTIONAL: Grant a power-up when consuming Wildcard/Joker (*) or Plus Wildcard (+) tiles in a merge
   121→    // (on use, not on creation)
   122→    //
   123→    // Important: Jokers can be "activated" (converted into a normal tile value) during match detection.
   124→    // In that case, `isJoker(t)` will be false here. We therefore also look at
   125→    // `game.activatedJokerPositions` (filled in match-detector.js during the user swap).
   126→    if (game.powerUpOnSpecialTileUseEnabled) {
   127→        matchGroups.forEach((group) => {
   128→            const usedWildcard = group.tiles.some((pos) => {
   129→                const t = game.board[pos.row][pos.col];
   130→                if (isJoker(t) || isTilePlusTile(t)) return true;
   131→
   132→                const key = `${pos.row}_${pos.col}`;
   133→                return game.activatedJokerPositions?.has?.(key) === true;
   134→            });
   135→
   136→            if (usedWildcard) {
   137→                game.grantRandomPowerUp();
   138→            }
   139→        });
   140→
   141→        // Clear after processing the first merge step so we don't accidentally
   142→        // reward later cascades for an earlier joker activation.
   143→        // Set to null so it gets properly re-initialized on the next swap.
   144→        game.activatedJokerPositions = null;
   145→    }
   146→
   147→    // Update cursed goal progress for successfully merged cursed tiles
   148→    mergedCursedTiles.forEach((pos) => {
   149→        const tile = game.board[pos.row][pos.col];
   150→        const value = getTileValue(tile);
   151→        game.levelGoals.forEach((goal) => {
   152→            if (goal.goalType === "cursed" && goal.tileValue === value) {
   153→                goal.current++;
   154→            }
   155→        });
   156→    });
   157→
   158→    // Track match statistics (only for user-initiated matches)
   159→    if (wasUserSwap) {
   160→        matchGroups.forEach((group) => {
   161→            const tileCount = group.tiles.length;
   162→            const direction = group.direction;
   163→
   164→            if (direction === "T-formation") {
   165→                game.matchStats.tFormationCount++;
   166→            } else if (direction === "L-formation") {
   167→                game.matchStats.lFormationCount++;
   168→            } else if (direction === "block_4_formation") {
   169→                game.matchStats.blockFormationCount++;
   170→            } else if (tileCount === 5) {
   171→                game.matchStats.match5Count++;
   172→            } else if (tileCount === 4) {
   173→                game.matchStats.match4Count++;
   174→            } else if (tileCount === 3) {
   175→                game.matchStats.match3Count++;
   176→            }
   177→
   178→            // Grant power-up for 5-tile formations (L, T, 5-line)
   179→            if (
   180→                direction === "L-formation" ||
   181→                direction === "T-formation" ||
   182→                direction === "line_5_horizontal" ||
   183→                direction === "line_5_vertical"
   184→            ) {
   185→                game.grantFormationPowerUp(direction);
   186→            }
   187→        });
   188→
   189→    }
   190→
   191→    // Clear all matched tiles first
   192→    matchGroups.forEach((group) => {
   193→        group.tiles.forEach((tile) => {
   194→            game.board[tile.row][tile.col] = null;
   195→        });
   196→    });
   197→
   198→    // Create new merged tiles
   199→    matchGroups.forEach((group) => {
   200→        createMergedTiles(game, group, wasUserSwap);
   201→    });
   202→
   203→    // Clear swap position after processing
   204→    game.lastSwapPosition = null;
   205→
   206→    // Update goal display after creating new tiles (without checking completion)
   207→    // Let the natural cascade completion in dropGems handle checkLevelComplete
   208→    game.updateGoalDisplay(false);
   209→
   210→    // Clean up animation classes
   211→    document.querySelectorAll(".gem").forEach((gem) => {
   212→        gem.classList.remove("sliding", "merge-target", "unblocking");
   213→        gem.style.transform = "";
   214→        gem.style.transition = "";
   215→        gem.style.opacity = "";
   216→        gem.style.zIndex = "";
   217→    });
   218→
   219→    // Re-render the board to show the merged tiles in their new state
   220→    // This is important so that when we animate tile removal, the board is in the correct state
   221→    game.renderBoard();
   222→
   223→    // Check if we need to shift tile levels before continuing with cascade
   224→    // This will animate the removal and then continue
   225→    if (game.pendingTileLevelShift) {
   226→        // Small delay to allow the render to complete
   227→        setTimeout(() => {
   228→            game.shiftTileLevels().then(() => {
   229→                game.dropGems();
   230→            });
   231→        }, 50);
   232→    } else {
   233→        game.dropGems();
   234→    }
   235→}
   236→
   237→export function createMergedTiles(game, group, wasUserSwap = false) {
   238→    const formationType = getFormationConfig(group.direction);
   239→    const specialTileType = formationType ? game.specialTileConfig[formationType] : null;
   240→
   241→    // Calculate positions and value based on formation type
   242→    const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
   243→    const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
   244→    const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(game, group.tiles, group);
   245→    const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
   246→
   247→    const newValue = group.value + valueIncrement;
   248→
   249→    // Check if sticky free swap should transfer (detected before tiles were cleared)
   250→    // If so, and this was NOT a user swap, transfer the sticky free swap to the merged tile
   251→    const hasStickyFreeSwap = group.hasStickyFreeSwap || false;
   252→    const transferStickyFreeSwap = hasStickyFreeSwap && !wasUserSwap;
   253→
   254→    // Track intermediate values for formations that skip a level (T, L, 5-line)
   255→    // When tiles of value N merge into 1 tile of value N+2, conceptually there's an intermediate step:
   256→    // - T/L formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
   257→    // - 5-line formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
   258→    // So we track 3 creations of the intermediate value (N+1)
   259→    if (isTLFormation || is5LineFormation) {
   260→        const intermediateValue = group.value + 1;
   261→        trackGoalProgress(game, intermediateValue, 3);
   262→    }
   263→
   264→    // Handle special tile types
   265→    if (specialTileType === "joker" || specialTileType === "wild_teleport") {
   266→        // Joker and wild_teleport are special - they create JOKER type tiles, not normal tiles with properties
   267→        const createSpecialTile = specialTileType === "wild_teleport" ? createWildTeleportTile : createJokerTile;
   268→
   269→        if (positions.length > 1) {
   270→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
   271→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
   272→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
   273→
   274→            game.board[specialPos.row][specialPos.col] = createSpecialTile();
   275→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
   276→            trackGoalProgress(game, newValue, 1);
   277→        } else {
   278→            game.board[positions[0].row][positions[0].col] = createSpecialTile();
   279→        }
   280→    } else if (specialTileType === "random_powerup") {
   281→        // Random power-up grants a power-up immediately and creates normal tiles
   282→        game.grantRandomPowerUp();
   283→        positions.forEach((pos) => {
   284→            game.board[pos.row][pos.col] = createTile(newValue, null, { transferStickyFreeSwap });
   285→        });
   286→        trackGoalProgress(game, newValue, positions.length);
   287→    } else if (specialTileType && specialTileType !== "none") {
   288→        // All other special tile types use the same pattern
   289→        // For directional free swaps, determine the direction
   290→        let options = { transferStickyFreeSwap };
   291→
   292→        if (specialTileType === "freeswap_horizontal" || specialTileType === "freeswap_vertical") {
   293→            // Determine swap direction from lastSwapPosition
   294→            let isHorizontal = false;
   295→            if (game.lastSwapPosition && game.lastSwapPosition.movedFrom) {
   296→                const fromRow = game.lastSwapPosition.movedFrom.row;
   297→                const toRow = game.lastSwapPosition.row;
   298→
   299→                // If rows are the same, it's a horizontal swap (columns differ)
   300→                isHorizontal = fromRow === toRow;
   301→            }
   302→            options.isHorizontal = isHorizontal;
   303→        }
   304→
   305→        if (positions.length > 1) {
   306→            // For 2-position formations (4-tile line/block), create one special tile and one normal tile
   307→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
   308→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
   309→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
   310→
   311→            game.board[specialPos.row][specialPos.col] = createTile(newValue, specialTileType, options);
   312→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
   313→            trackGoalProgress(game, newValue, 2);
   314→        } else {
   315→            // For 1-position formations (T, L, 5-line), create one special tile
   316→            game.board[positions[0].row][positions[0].col] = createTile(newValue, specialTileType, options);
   317→            trackGoalProgress(game, newValue, 1);
   318→        }
   319→    } else {
   320→        // No special tile - create normal tiles at all positions
   321→        // However, if transferStickyFreeSwap is true, the merged tiles should inherit the sticky free swap ability
   322→        positions.forEach((pos) => {
   323→            game.board[pos.row][pos.col] = createTile(newValue, null, { transferStickyFreeSwap });
   324→        });
   325→        trackGoalProgress(game, newValue, positions.length);
   326→    }
   327→
   328→    // After creating merged tiles, check if any should become cursed
   329→    positions.forEach((pos) => {
   330→        checkAndCreateCursedTile(game, newValue, pos);
   331→    });
   332→
   333→    // Check if we need to shift tile levels based on the newly created value
   334→    // This just sets a flag and the highest value reached, doesn't execute the shift yet
   335→    game.checkAndShiftTileLevels(newValue);
   336→
   337→    // Check if creating this value should grant a power-up reward
   338→    game.checkAndGrantPowerUpReward(newValue);
   339→}
   340→
   341→export function determineSpecialTilePosition(game, group, formationType) {
   342→    // For 4-tile formations, determine which of the 2 middle positions should get the special tile
   343→    // based on where the last swap was made
   344→    if (!game.lastSwapPosition) {
   345→        // If no swap info, default to first middle position
   346→        if (formationType === "block_4") {
   347→            return group.intersections[0];
   348→        } else {
   349→            const middlePositions = calculateMiddlePositions(game, group.tiles);
   350→            return middlePositions[0];
   351→        }
   352→    }
   353→
   354→    const swapPos = game.lastSwapPosition;
   355→
   356→    if (formationType === "block_4") {
   357→        // For block formation, choose the intersection closest to swap position
   358→        // First check if the swapped tile is one of the intersections
   359→        const matchingIntersection = group.intersections.find(
   360→            (pos) => pos.row === swapPos.row && pos.col === swapPos.col
   361→        );
   362→        if (matchingIntersection) {
   363→            return matchingIntersection;
   364→        }
   365→
   366→        // Otherwise, find which intersection is adjacent to the swapped position
   367→        // The 2x2 block has positions at [r,c], [r,c+1], [r+1,c], [r+1,c+1]
   368→        // Intersections are at [r,c+1] (top-right) and [r+1,c] (bottom-left)
   369→        const adjacentIntersection = group.intersections.find((pos) => {
   370→            const isAdjacent =
   371→                (Math.abs(pos.row - swapPos.row) === 1 && pos.col === swapPos.col) ||
   372→                (Math.abs(pos.col - swapPos.col) === 1 && pos.row === swapPos.row);
   373→            return isAdjacent;
   374→        });
   375→
   376→        if (adjacentIntersection) {
   377→            return adjacentIntersection;
   378→        }
   379→
   380→        // Fallback to distance-based (shouldn't reach here in normal gameplay)
   381→        const distances = group.intersections.map((pos) => {
   382→            const dist = Math.abs(pos.row - swapPos.row) + Math.abs(pos.col - swapPos.col);
   383→            return { pos, dist };
   384→        });
   385→        distances.sort((a, b) => a.dist - b.dist);
   386→        return distances[0].pos;
   387→    } else if (formationType === "line_4") {
   388→        // For line formation, choose the middle position that contains the swapped tile
   389→        const middlePositions = calculateMiddlePositions(game, group.tiles);
   390→
   391→        // Check if swap position matches one of the middle positions
   392→        const matchingPos = middlePositions.find((pos) => pos.row === swapPos.row && pos.col === swapPos.col);
   393→
   394→        if (matchingPos) {
   395→            return matchingPos;
   396→        }
   397→
   398→        // If swap position doesn't match, choose closest middle position
   399→        const distances = middlePositions.map((pos) => {
   400→            const dist = Math.abs(pos.row - swapPos.row) + Math.abs(pos.col - swapPos.col);
   401→            return { pos, dist };
   402→        });
   403→        distances.sort((a, b) => a.dist - b.dist);
   404→        return distances[0].pos;
   405→    }
   406→
   407→    return null;
   408→}
   409→
   410→function getFormationConfig(direction) {
   411→    // Map direction to formation type for special tile config
   412→    const formationMap = {
   413→        "T-formation": "t_formation",
   414→        "L-formation": "l_formation",
   415→        block_4_formation: "block_4",
   416→        line_4_horizontal: "line_4",
   417→        line_4_vertical: "line_4",
   418→        line_5_horizontal: "line_5",
   419→        line_5_vertical: "line_5",
   420→    };
   421→
   422→    return formationMap[direction] || null;
   423→}
   424→
   425→function calculateMiddlePositions(game, tiles, group = null) {
   426→    const positions = [];
   427→    const length = tiles.length;
   428→
   429→    // Special handling for T and L formations
   430→    if (group && (group.direction === "T-formation" || group.direction === "L-formation")) {
   431→        // For special formations, the "middle" position is the intersection
   432→        positions.push(group.intersection);
   433→        return positions;
   434→    }
   435→
   436→    // Special handling for block formations
   437→    if (group && group.direction === "block_4_formation") {
   438→        // For block formations, the "middle" positions are the two intersections
   439→        return group.intersections;
   440→    }
   441→
   442→    // Special handling for 5-tile lines (should create 1 tile with 4x value)
   443→    if (group && (group.direction === "line_5_horizontal" || group.direction === "line_5_vertical")) {
   444→        // 5 tiles: middle position only (creates 1 tile with 4x value)
   445→        positions.push(tiles[2]);
   446→        return positions;
   447→    }
   448→
   449→    // Regular match logic
   450→    if (length === 3) {
   451→        // 3 tiles: middle position (creates 1 tile with 2x value)
   452→        positions.push(tiles[1]);
   453→    } else if (length === 4) {
   454→        // 4 tiles: two middle positions (creates 2 tiles with 2x value)
   455→        positions.push(tiles[1]);
   456→        positions.push(tiles[2]);
   457→    } else if (length >= 5) {
   458→        // 5+ tiles: single middle position (creates 1 tile with 4x value)
   459→        positions.push(tiles[Math.floor(length / 2)]);
   460→    }
   461→
   462→    return positions;
   463→}
   464→
   465→function unblockAdjacentTiles(game, matchGroups, speedMultiplier = 1) {
   466→    const blockedTilesToRemove = [];
   467→    const goalTilesToDamage = [];
   468→    const cellsToDecrement = new Set(); // Track individual cells to decrement for merge-count blocks
   469→
   470→    matchGroups.forEach((group) => {
   471→        // Track which blocked tiles have been hit by this match group
   472→        const hitInThisGroup = new Set();
   473→
   474→        // Get where the new merged tile(s) will be created
   475→        let targetPositions = [];
   476→        if (group.direction === "T-formation" || group.direction === "L-formation") {
   477→            targetPositions.push(group.intersection);
   478→        } else if (group.direction === "block_4_formation") {
   479→            targetPositions.push(...group.intersections);
   480→        } else {
   481→            const middlePositions = calculateMiddlePositions(game, group.tiles, group);
   482→            targetPositions.push(...middlePositions);
   483→        }
   484→
   485→        // Calculate the damage value from this match (the value of tiles being matched, not the merged result)
   486→        const damageValue = getDisplayValue(group.value);
   487→
   488→        // Check each tile in the original match for adjacent blocked/goal tiles
   489→        group.tiles.forEach((matchTile) => {
   490→            const adjacentPositions = [
   491→                { row: matchTile.row - 1, col: matchTile.col }, // Up
   492→                { row: matchTile.row + 1, col: matchTile.col }, // Down
   493→                { row: matchTile.row, col: matchTile.col - 1 }, // Left
   494→                { row: matchTile.row, col: matchTile.col + 1 }, // Right
   495→            ];
   496→
   497→            adjacentPositions.forEach((pos) => {
   498→                // Check bounds
   499→                if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
   500→                    const tile = game.board[pos.row][pos.col];
   501→
   502→                    // Handle blocked tiles and blocked movable tiles (remove immediately)
   503→
   504→                    // Handle blocked tiles with life (apply damage)
   505→                    if (isBlockedWithLife(tile)) {
   506→                        // Use rectId for rectangular blocks, row_col for single cells
   507→                        const key = isRectangularBlocked(tile) ? tile.rectId : `${pos.row}_${pos.col}`;
   508→
   509→                        // Skip if already hit by this match group
   510→                        if (hitInThisGroup.has(key)) {
   511→                            return;
   512→                        }
   513→                        hitInThisGroup.add(key);
   514→
   515→                        const existingEntry = goalTilesToDamage.find((t) => t.key === key);
   516→
   517→                        if (existingEntry) {
   518→                            // Accumulate damage from different match groups
   519→                            existingEntry.damage += damageValue;
   520→                        } else {
   521→                            // Find the closest target position for animation
   522→                            let closestTarget = targetPositions[0];
   523→                            let closestDistance =
   524→                                Math.abs(pos.row - closestTarget.row) + Math.abs(pos.col - closestTarget.col);
   525→
   526→                            targetPositions.forEach((target) => {
   527→                                const distance = Math.abs(pos.row - target.row) + Math.abs(pos.col - target.col);
   528→                                if (distance < closestDistance) {
   529→                                    closestDistance = distance;
   530→                                    closestTarget = target;
   531→                                }
   532→                            });
   533→
   534→                            goalTilesToDamage.push({
   535→                                key: key,
   536→                                row: pos.row,
   537→                                col: pos.col,
   538→                                damage: damageValue,
   539→                                targetPos: closestTarget,
   540→                                tile: tile, // Store tile reference for rectangular blocks
   541→                            });
   542→                        }
   543→                    }
   544→                    // Handle blocked tiles with merge count (per-rectangle tracking)
   545→                    else if (isBlockedWithMergeCount(tile)) {
   546→                        // Skip if this RECTANGLE was already hit in this match group
   547→                        // One match should only clear ONE cell from the entire block
   548→                        if (hitInThisGroup.has(tile.rectId)) {
   549→                            return;
   550→                        }
   551→                        hitInThisGroup.add(tile.rectId);
   552→
   553→                        // Find any cell in this rectangle that still needs clearing
   554→                        // Also check cellsToDecrement to avoid picking a cell already claimed by another match group
   555→                        let cellToClear = null;
   556→                        for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
   557→                            for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
   558→                                const cellKey = `${r}_${c}`;
   559→                                const rectCellKey = `${tile.rectId}_${cellKey}`;
   560→                                // Only consider cells that have count > 0 AND haven't been claimed by another match
   561→                                if (tile.cellMergeCounts[cellKey] > 0 && !cellsToDecrement.has(rectCellKey)) {
   562→                                    cellToClear = { row: r, col: c, cellKey: cellKey };
   563→                                    break;
   564→                                }
   565→                            }
   566→                            if (cellToClear) break;
   567→                        }
   568→
   569→                        // If we found a cell to clear, decrement it
   570→                        if (cellToClear) {
   571→                            const rectCellKey = `${tile.rectId}_${cellToClear.cellKey}`;
   572→                            cellsToDecrement.add(rectCellKey);
   573→
   574→                            // Find the closest target position for animation
   575→                            let closestTarget = targetPositions[0];
