   708→export function checkAndCreateCursedTile(game, value, position) {
   709→    // Check if this value has a cursed goal
   710→    const cursedGoal = game.levelGoals.find((goal) => goal.goalType === "cursed" && goal.tileValue === value);
   711→
   712→    if (!cursedGoal) {
   713→        return false; // No cursed goal for this value
   714→    }
   715→
   716→    // Check if cursed goal is already complete
   717→    if (cursedGoal.current >= cursedGoal.target) {
   718→        return false; // Goal complete, no more cursed tiles
   719→    }
   720→
   721→    // Special handling for frequency: 0
   722→    // Always keep exactly one cursed tile on the board
   723→    if (cursedGoal.frequency === 0) {
   724→        // Check if we already created one this turn (to prevent multiple during cascades)
   725→        if (game.cursedTileCreatedThisTurn[value]) {
   726→            return false;
   727→        }
   728→
   729→        // Scan the entire board to count cursed tiles of this value
   730→        let cursedCount = 0;
   731→        for (let row = 0; row < game.boardHeight; row++) {
   732→            for (let col = 0; col < game.boardWidth; col++) {
   733→                const tile = game.board[row][col];
   734→                if (tile && isCursed(tile) && getTileValue(tile) === value) {
   735→                    cursedCount++;
   736→                }
   737→            }
   738→        }
   739→
   740→        // Only create if none exist
   741→        if (cursedCount === 0) {
   742→            const currentTile = game.board[position.row][position.col];
   743→            if (currentTile && getTileValue(currentTile) === value) {
   744→                const cursedTile = createCursedTile(value, cursedGoal.strength);
   745→                game.board[position.row][position.col] = cursedTile;
   746→                game.cursedTileCreatedThisTurn[value] = true; // Mark as created this turn
   747→                return true;
   748→            }
   749→        }
   750→        return false;
   751→    }
   752→
   753→    // Normal frequency handling (frequency >= 1)
   754→    // Track how many tiles of this value have been created
   755→    if (!game.cursedTileCreatedCount[value]) {
   756→        game.cursedTileCreatedCount[value] = 0;
   757→    }
   758→    game.cursedTileCreatedCount[value]++;
   759→
   760→    // Check if frequency is met (every Nth tile becomes cursed)
   761→    if (game.cursedTileCreatedCount[value] % cursedGoal.frequency === 0) {
   762→        // Convert the tile at this position to a cursed tile
   763→        const currentTile = game.board[position.row][position.col];
   764→        if (currentTile && getTileValue(currentTile) === value) {
   765→            // Create cursed tile with full strength - decrement will happen at end of turn
   766→            const cursedTile = createCursedTile(value, cursedGoal.strength);
   767→            game.board[position.row][position.col] = cursedTile;
   768→
   769→            return true; // Cursed tile created
   770→        }
   771→    }
   772→
   773→    return false; // Not cursed
   774→}
