     7→export function animateSwap(game, row1, col1, row2, col2, callback) {
     8→    game.animating = true;
     9→
    10→    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
    11→    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
    12→
    13→    if (gem1 && gem2) {
    14→        const rect1 = gem1.getBoundingClientRect();
    15→        const rect2 = gem2.getBoundingClientRect();
    16→
    17→        const deltaX = rect2.left - rect1.left;
    18→        const deltaY = rect2.top - rect1.top;
    19→
    20→        // Animate both gems swapping positions
    21→        gem1.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
    22→        gem2.style.transform = `translate(${-deltaX}px, ${-deltaY}px)`;
    23→        gem1.style.transition = "transform 0.3s ease-out";
    24→        gem2.style.transition = "transform 0.3s ease-out";
    25→        gem1.style.zIndex = "100";
    26→        gem2.style.zIndex = "100";
    27→
    28→        setTimeout(() => {
    29→            // Clean up transform and transition
    30→            gem1.style.transform = "";
    31→            gem2.style.transform = "";
    32→            gem1.style.transition = "";
    33→            gem2.style.transition = "";
    34→            gem1.style.zIndex = "";
    35→            gem2.style.zIndex = "";
    36→
    37→            // Execute callback (render board and process matches)
    38→            // Note: callback (processMatches) will handle setting this.animating = false
    39→            if (callback) callback();
    40→        }, 300);
    41→    } else {
    42→        // Fallback if elements not found
    43→        if (callback) callback();
    44→    }
    45→}
