   153→    // For multiple targets, assign each tile to its nearest target
   154→    // Track how many tiles are assigned to each target for balanced distribution
   155→    const targetCounts = new Map();
   156→    targetPositions.forEach((pos) => {
   157→        targetCounts.set(`${pos.row},${pos.col}`, 0);
   158→    });
   159→
   160→    const assignments = [];
