   162→    // Sort outer tiles to process them in a consistent order
   163→    const sortedOuterTiles = [...outerTiles].sort((a, b) => {
   164→        if (a.row !== b.row) return a.row - b.row;
   165→        return a.col - b.col;
   166→    });
   167→
   168→    for (const tile of sortedOuterTiles) {
   169→        // Find the nearest target position
   170→        let bestTarget = targetPositions[0];
   171→        let bestDistance = Math.abs(tile.row - bestTarget.row) + Math.abs(tile.col - bestTarget.col);
   172→
   173→        for (const target of targetPositions) {
   174→            const distance = Math.abs(tile.row - target.row) + Math.abs(tile.col - target.col);
   175→            if (distance < bestDistance) {
   176→                bestDistance = distance;
   177→                bestTarget = target;
   178→            }
   179→        }
   180→
   181→        assignments.push({ tile, target: bestTarget });
   182→        const key = `${bestTarget.row},${bestTarget.col}`;
   183→        targetCounts.set(key, targetCounts.get(key) + 1);
   184→    }
   185→
   186→    return assignments;
   187→}
