   229→function animateRectangularBlockRemoval(game, tile, speedMultiplier = 1) {
   230→    // Find the DOM element by rectId
   231→    const blockedElement = document.querySelector(`[data-rect-id="${tile.rectId}"]`);
   232→
   233→    if (blockedElement) {
   234→        blockedElement.classList.add("disappear");
   235→    }
   236→
   237→    // Capture the rectId and dimensions before the timeout
   238→    // (in case the tile object reference changes due to hint system board restoration)
   239→    const rectId = tile.rectId;
   240→    const anchorRow = tile.rectAnchor.row;
   241→    const anchorCol = tile.rectAnchor.col;
   242→    const rectHeight = tile.rectHeight;
   243→    const rectWidth = tile.rectWidth;
   244→
   245→    // Remove from ALL cells of the rectangle
   246→    setTimeout(() => {
   247→        for (let r = anchorRow; r < anchorRow + rectHeight; r++) {
   248→            for (let c = anchorCol; c < anchorCol + rectWidth; c++) {
   249→                // Use rectId comparison instead of object identity
   250→                // (hint system may have replaced objects with shallow copies)
   251→                const boardTile = game.board[r]?.[c];
   252→                if (boardTile && boardTile.rectId === rectId) {
   253→                    game.board[r][c] = null;
   254→                }
   255→            }
   256→        }
   257→    }, 400 * speedMultiplier);
   258→}
