.game-container {
    text-align: center;
    max-width: 600px;
    width: 100%;
    height: 100dvh;
    padding: 10px clamp(10px, 3vw, 20px);
    display: none;
    flex-direction: column;
    justify-content: center;
    gap: clamp(8px, 4vw, 20px);
    position: relative;
    overflow: hidden;
    touch-action: none;
    overscroll-behavior: none;
}

.back-btn {
    position: absolute;
    top: calc(10px + env(safe-area-inset-top));
    left: clamp(10px, 3vw, 20px);
    background: #141414;
    border: 3px solid #000;
    border-radius: 35%;
    width: clamp(30px, 6vw, 40px);
    height: clamp(30px, 6vw, 40px);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: clamp(16px, 4vw, 24px);
    z-index: 10;
    color: rgba(255, 255, 255, 0.8);
    padding-bottom: 2px;
}

.game-info-btn {
    position: absolute;
    top: calc(10px + env(safe-area-inset-top));
    right: clamp(10px, 3vw, 20px);
    background: #141414;
    border: 3px solid #000;
    border-radius: 35%;
    width: clamp(30px, 6vw, 40px);
    height: clamp(30px, 6vw, 40px);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: clamp(16px, 4vw, 24px);
    font-family: Nunito;
    font-weight: 900;
    z-index: 10;
    color: rgba(255, 255, 255, 0.8);
}

.top-spacer {
    flex: 1 999 0;
    min-height: 0;
    justify-content: center;
    display: flex;
    align-items: center;
}

.level-text {
    margin: 0;
    color: rgba(255, 255, 255, 0.5);
    font-family: Nunito;
    font-size: 32px;
    font-style: normal;
    font-weight: 900;
    line-height: normal;
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 100;
    pointer-events: none;
    width: 90%;
}

#levelSolvedSvg {
    position: relative;
}

#levelFailedSvg {
    position: absolute;
    width: 100%;
    left: 0;
    top: 0;
}

#failReasonText {
    position: absolute;
    width: 100%;
    left: 0;
    top: 50px;
}

#levelSolvedSvg.animate {
    animation: levelSolvedBounce 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

#levelFailedSvg.animate {
    animation: levelFailedBounce 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes levelSolvedBounce {
    0% {
        opacity: 0;
        transform: scale(0.3);
    }
    50% {
        opacity: 1;
        transform: scale(1.15);
    }
    70% {
        transform: scale(0.9);
    }
    85% {
        transform: scale(1.05);
    }
    100% {
        transform: scale(1);
        opacity: 1;
    }
}

@keyframes levelFailedBounce {
    0% {
        opacity: 0;
        transform: scale(0.3);
    }
    50% {
        opacity: 1;
        transform: scale(1.15);
    }
    70% {
        transform: scale(0.9);
    }
    85% {
        transform: scale(1.05);
    }
    100% {
        transform: scale(1);
        opacity: 1;
    }
}

.game-info {
    display: flex;
    gap: clamp(10px, 3vw, 20px);
    justify-content: center;
    align-items: center;
    flex-shrink: 0;
    width: 100%;
    align-items: stretch;
    min-height: 80px;
}

.goals-container,
.moves-container,
.board-upgrades-container {
    position: relative;
    border-radius: 24px;
    border: 3px solid #000;
    background: #141414;

    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
}

.goals-container .label,
.moves-container .label,
.board-upgrades-container .label {
    position: absolute;
    top: -15px;
    left: 50%;
    transform: translateX(-50%);
    font-family: Nunito;
    font-size: 22px;
    font-style: normal;
    font-weight: 900;
    line-height: normal;
    white-space: nowrap;
}

.goals-container {
    flex: 1;
    padding: 25px 0 5px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.board-upgrades-container {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 10px 16px;
}

.board-upgrades-container .label {
    top: -18px;
}

.board-upgrades {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.upgrade-icon {
    height: 1.5rem;
}

.upgrade-icon.active {
    filter: drop-shadow(0 0 8px rgba(218, 34, 255, 0.8));
}

.upgrade-tile {
    width: 30px;
    height: 30px;
    opacity: 1;
    transition: opacity 0.3s ease;
}

.upgrade-tile.completed {
    opacity: 0.4;
    filter: grayscale(0.5);
}

/* Power-Up Rewards Container - 3 columns matching power-up buttons */
.powerup-rewards-container {
    display: flex;
    align-items: stretch;
    justify-content: center;
    gap: clamp(8px, 2vw, 16px); /* Same gap as .power-ups */
    border-radius: 16px;
    background: #141414a2;
    width: fit-content;
    align-self: center;
    padding: 8px 0;
    margin: 6px auto 0px;
    position: relative;
}

.powerup-rewards-container .label {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    position: absolute;
    left: -33px;
    top: -3px;
}

.powerup-reward-column {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-end;
    width: clamp(60px, 20vw, 120px); /* Same width as power-up buttons */
    /* min-height: 30px; */
    gap: 4px;
}

.powerup-reward-column .column-tiles {
    display: flex;
    flex-direction: row;
    flex-wrap: wrap;
    gap: 4px;
    justify-content: center;
    align-items: center;
}

.powerup-reward-tile {
    width: 24px;
    height: 24px;
    transition:
        opacity 0.3s ease,
        filter 0.3s ease;
}

.powerup-reward-tile.completed {
    opacity: 0.4;
    filter: grayscale(0.5);
}

.goals-container .crown {
    position: absolute;
    top: -34px;
    left: 50%;
    transform: translateX(-50%);
    width: 60px;
    height: 34px;
}

.moves-container {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 12px;
    flex: 1;
    max-width: 100px;
}

.moves-container span {
    color: #fff;
    text-shadow:
        -2px -2px 0 #222,
        2px -2px 0 #222,
        -2px 2px 0 #222,
        2px 2px 0 #222;
    font-family: Nunito;
    font-size: 40px;
    font-style: normal;
    font-weight: 900;
}

.goals {
    display: flex;
    gap: clamp(6px, 2vw, 10px);
    justify-content: center;
    height: fit-content;
    align-items: center;
}

.goal-card {
    min-width: clamp(60px, 25%, 80px);
    position: relative;
}

.goal-icon {
    position: absolute;
    top: -12px;
    left: 50%;
    transform: translateX(-50%);
    background: #141414;
    border-radius: 35%;
    font-size: 1rem;
    line-height: 1rem;
    width: 1.2rem;
    height: 1.2rem;
    text-align: center;
    display: none;
}

.goal-score {
    .goal-icon {
        width: unset;
        color: #898989;
        font-family: "Nunito";
        font-size: 0.8em;
