    font-size: clamp(16px, 3vw, 24px);
    font-weight: 900;
    color: #45413d;
    container-type: inline-size;
    container-name: card;
    padding-bottom: 2px;
    outline-color: rgba(0, 0, 0, 0);

    -webkit-tap-highlight-color: transparent;
