    const dmgText = document.createElement("span");
    dmgText.className = "damage-text";
    dmgText.textContent = `-${entry.damage}`;
    el.appendChild(dmgText);

    setTimeout(() => {
        el.classList.remove("blocked-damaged");
        dmgText.remove();
    }, 800);
}

